import { useEffect, useState } from "react";
import api from "../api";
import { useAuth, hasRole } from "../AuthContext";

export default function Dashboard() {
    const { user } = useAuth();
    const isAdmin = hasRole(user, "ADMIN");
    const isSales = hasRole(user, "SALES");
    const isAcc   = hasRole(user, "ACCOUNTANT");

    const [summary, setSummary] = useState({ customers: 0, contracts: 0, paid: 0, remaining: 0 });
    const [recentContracts, setRecentContracts] = useState([]);
    const [upcomingEvents, setUpcomingEvents] = useState([]);

    useEffect(() => {
        (async () => {
            // 1) Summary: ACCOUNTANT vẫn được xem
            try {
                const s = await api.get("/api/dashboard/summary");
                setSummary(s.data || {});
            } catch (e) {
                // nếu 403/401 thì để mặc định (0)
                if (e?.response?.status !== 403) console.error(e);
            }

            // 2) Recent contracts: cho tất cả (backend tự lọc theo role)
            try {
                const rc = await api.get("/api/dashboard/recent-contracts");
                setRecentContracts(rc.data || []);
            } catch (e) {
                if (e?.response?.status !== 403) console.error(e);
            }

            // 3) Events: chỉ Admin/Sales mới gọi
            if (isAdmin || isSales) {
                try {
                    const ev = await api.get("/api/events/me?nextDays=30");
                    setUpcomingEvents(ev.data || []);
                } catch (e) {
                    if (e?.response?.status !== 403) console.error(e);
                }
            } else {
                setUpcomingEvents([]); // accountant: chắc chắn rỗng
            }

            // 4) Customers count (nếu bạn đang hiển thị ô "Khách hàng"):
            // chỉ Admin/Sales mới gọi, ACCOUNTANT không gọi để tránh 403
            if (isAdmin || isSales) {
                try {
                    const c = await api.get("/api/customers/count");
                    setSummary((s) => ({ ...s, customers: c.data ?? 0 }));
                } catch (e) {
                    if (e?.response?.status !== 403) console.error(e);
                }
            }
        })();
    }, [isAdmin, isSales, isAcc]);

    // ... phần render giữ nguyên, NHƯNG các card "Khách hàng" và widget "Sự kiện"
    // chỉ render cho (isAdmin || isSales) như mình đã gửi ở bước trước.
    // (đừng quên ẩn cả link "Xem tất cả" của events nếu là ACC)
}
